const puppeteer=require('puppeteer'),path=require('path');
(async()=>{const f=process.argv[2];const b=await puppeteer.launch({headless:'new',args:['--no-sandbox','--disable-gpu','--force-color-profile=srgb']});const p=await b.newPage();await p.setViewport({width:880,height:840,deviceScaleFactor:2});await p.goto('file://'+path.join(__dirname,f),{waitUntil:'networkidle0'});await new Promise(r=>setTimeout(r,250));await p.screenshot({path:path.join(__dirname,f.replace('.html','.png')),fullPage:true});await b.close();console.log('done')})().catch(e=>{console.error(e);process.exit(1)});
